import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How much down payment do you need to buy a house?", a: "Some programs allow 3% to 3.5% down, while 20% down commonly avoids private mortgage insurance. Requirements depend on loan type and lender rules." },
  { q: "What is PMI and when is it required?", a: "PMI is private mortgage insurance. Conventional loans often require it when the down payment is below 20%." },
  { q: "How do you save for a down payment?", a: "Set a target price, choose a down payment percentage, automate monthly savings, and keep the money in a low-risk account until purchase." },
  { q: "What are down payment assistance programs?", a: "These are grants, forgivable loans, or low-interest programs from states, cities, employers, or nonprofits that help qualified buyers cover upfront costs." },
  { q: "Is a bigger down payment always better?", a: "A bigger down payment can reduce monthly cost and PMI, but it may not be ideal if it drains emergency savings or delays other goals." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function pmt(principal: number, rate: number, years: number) {
  const r = rate / 100 / 12;
  const n = years * 12;
  if (principal <= 0 || n <= 0) return 0;
  return r === 0 ? principal / n : principal * r / (1 - Math.pow(1 + r, -n));
}

function scenario(home: number, pct: number, rate = 6.5) {
  const down = home * pct / 100;
  const loan = home - down;
  const pmi = pct < 20 ? loan * 0.006 / 12 : 0;
  return { pct, down, loan, payment: pmt(loan, rate, 30) + pmi, pmi };
}

export default function DownPaymentCalculator() {
  useCurrencyVersion();
  const [homePrice, setHomePrice] = useState(350000);
  const [downPct, setDownPct] = useState(10);
  const [downAmount, setDownAmount] = useState(35000);
  const [mode, setMode] = useState<"percent" | "amount">("percent");
  const [rate, setRate] = useState(6.5);

  const result = useMemo(() => {
    const down = mode === "percent" ? homePrice * downPct / 100 : downAmount;
    const pct = homePrice > 0 ? down / homePrice * 100 : 0;
    const loan = Math.max(0, homePrice - down);
    const pmi = pct < 20 ? loan * 0.006 / 12 : 0;
    return { down, pct, loan, pmi, monthly: pmt(loan, rate, 30) + pmi, pmiRequired: pct < 20 };
  }, [homePrice, downPct, downAmount, mode, rate]);

  const rows = [3, 3.5, 5, 10, 15, 20, 25].map((pct) => scenario(350000, pct, 6.5));

  return (
    <>
      <SEOHead title="Free Down Payment Calculator Online - Calculate Home Down Payment Amount Instantly | CalcHive" description="Free online down payment calculator. Calculate down payment amount, loan amount, PMI requirement and monthly payment for any home price and down payment percentage instantly. 100% free, no signup required." canonical="/down-payment-calculator" keywords="free down payment calculator, home down payment calculator free online, how much down payment calculator free, mortgage down payment calculator free, PMI calculator free online" category="Financial Calculators" breadcrumbName="Free Down Payment Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Down Payment Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate down payment amount, loan amount, PMI, and estimated monthly payment.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Home price</label><input type="number" value={homePrice} onChange={(e) => setHomePrice(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Entry mode</label><select value={mode} onChange={(e) => setMode(e.target.value as "percent" | "amount")} className={inputClass}><option value="percent">Down payment percent</option><option value="amount">Down payment amount</option></select></div>{mode === "percent" ? <div><label className="text-sm font-semibold text-foreground block mb-2">Down payment (%)</label><input type="number" value={downPct} onChange={(e) => { const next = Number(e.target.value); setDownPct(next); setDownAmount(homePrice * next / 100); }} className={inputClass} /></div> : <div><label className="text-sm font-semibold text-foreground block mb-2">Down payment amount</label><input type="number" value={downAmount} onChange={(e) => { const next = Number(e.target.value); setDownAmount(next); setDownPct(homePrice > 0 ? next / homePrice * 100 : 0); }} className={inputClass} /></div>}<div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Down Payment Amount</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.down)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Loan amount</p><p className="text-lg font-extrabold text-foreground">{money(result.loan)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">PMI required</p><p className="text-lg font-extrabold text-foreground">{result.pmiRequired ? "Yes" : "No"}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Monthly payment</p><p className="text-lg font-extrabold text-foreground">{money(result.monthly)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Your Home Down Payment for Free</h2><p className="text-muted-foreground leading-relaxed">Multiply the home price by your down payment percentage, or enter a dollar amount directly to see the matching percentage.</p><h2 className="text-2xl font-bold text-foreground">How Down Payment Amount Affects Monthly Payment and PMI</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Down Payment Impact on $350,000 Home at 6.5%</caption><thead className="bg-muted/60"><tr>{["Down Payment %", "Down Payment Amount", "Loan Amount", "Monthly Payment", "PMI Required", "Monthly PMI Cost"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row.pct}><td className="py-2.5 px-3 font-semibold">{row.pct}%</td><td className="py-2.5 px-3">{money(row.down, 0)}</td><td className="py-2.5 px-3">{money(row.loan, 0)}</td><td className="py-2.5 px-3">{money(row.payment)}</td><td className="py-2.5 px-3">{row.pct < 20 ? "Yes" : "No"}</td><td className="py-2.5 px-3">{money(row.pmi)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Home Down Payment Tool for Every Home Buyer</h2><p className="text-muted-foreground leading-relaxed">Use the down payment scenarios to compare affordability before choosing a mortgage program.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/down-payment-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


